"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[1726],{5615:(D,B,e)=>{e.r(B),e.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-27f3b386","path":"/kibernetiko/%D1%81%D0%BE%D0%B2%D1%80%D0%B5%D0%BC%D0%B5%D0%BD%D0%BD%D0%B0%D1%8F-%D1%82%D0%B5%D1%85%D0%BD%D0%B8%D0%BA%D0%B0-%D0%B8-%D0%B8%D0%B4%D0%B5%D1%8F-%D0%BE%D0%B3%D0%B0%D1%81-%D0%BC%D0%BE%D0%B4%D0%B5%D0%BB%D0%B8-%D0%B4%D0%B0%D0%BD%D0%BD%D1%8B%D1%85-%D0%B8-%D0%B4%D0%B5%D0%BC%D0%BE%D0%BA%D1%80%D0%B0%D1%82%D0%B8%D0%B7%D0%BC.html","title":"Современная техника и идея ОГАС: модели данных и демократизм","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[{"level":2,"title":"Список использованных источников","slug":"список-использованных-источников","link":"#список-использованных-источников","children":[]}],"git":{"updatedTime":1731854302000},"filePathRelative":"kibernetiko/современная-техника-и-идея-огас-модели-данных-и-демократизм.md"}')},473:(D,B,e)=>{e.r(B),e.d(B,{default:()=>p});var l=e(6252);const a=(0,l._)("h1",{id:"современная-техника-и-идея-огас-модели-данных-и-демократизм",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#современная-техника-и-идея-огас-модели-данных-и-демократизм","aria-hidden":"true"},"#"),(0,l.Uk)(" Современная техника и идея ОГАС: модели данных и демократизм")],-1),r={href:"https://research.comtext.space/data/dulingva/%D1%81%D0%BE%D0%B2%D1%80%D0%B5%D0%BC%D0%B5%D0%BD%D0%BD%D0%B0%D1%8F-%D1%82%D0%B5%D1%85%D0%BD%D0%B8%D0%BA%D0%B0-%D0%B8-%D0%B8%D0%B4%D0%B5%D1%8F-%D0%BE%D0%B3%D0%B0%D1%81-%D0%BC%D0%BE%D0%B4%D0%B5%D0%BB%D0%B8-%D0%B4%D0%B0%D0%BD%D0%BD%D1%8B%D1%85-%D0%B8-%D0%B4%D0%B5%D0%BC%D0%BE%D0%BA%D1%80%D0%B0%D1%82%D0%B8%D0%B7%D0%BC.html",target:"_blank",rel:"noopener noreferrer"},t=(0,l._)("p",null,"Какое место понятие о модели данных занимало в проектах ОГАС и в мыслях В. М. Глушкова? По своему происхождению оно формируется на основе развитых средств программирования, когда речь идет о том, что техника уже позволяет несколькими способами одинаково правильно реализовать общественный смысл программы или группы программ. Рост количества программ со временем порождает ситуацию, когда одни и те же данные в безбумажной форме используются несколькими программами разных назначений. Такая ситуация становится толчком к формированию отдельных программ для обобществления данных — СУБД, смысл которых изначально ограничивается поддержанием доступности и согласованности (формального качества) данных для программистов, использующих их в своих программах. Таким образом уже изначально СУБД употреблялись, в том числе и для некоторой экономии труда программистов ибо эти комплексы программ имели в своем составе типовые алгоритмы, которые в значительной степени независимы от общественного смысла данных. Дальнейшая экономия труда программистов через СУБД уже в середине 1970-х годов привела к формированию отдельной проблемы внутренней организации баз данных. Причем эта проблема формировалась не только в связи с особенностями техники, но и с тем как эту внутреннюю организацию БД трудно или легко понять человеку, который имеет потребности по применению соответствующих данных в своей практике и впервые попытается выяснить общественное пространство этого непосредственно (реже) или с помощью программистов (чаще). Насколько знание о структуре БД будет исключительным, насколько эта структура будет общепонятной — эти вопросы относительно ОГАС приобретают значение уже не в отношении экономии труда программистов и машинного времени. Этот вопрос, глядя на всеобщие перспективы ОГАС и ее необходимую популяризацию Глушков рассматривал как имеющий политическое значение. Потому что очевидно, что ОГАС очень легко представить как средство народного контроля и вообще демократизации многих общественных процессов.",-1),n=(0,l._)("p",null,'Между современными исследователями наиболее известен проект ОГАС 1980-го года, который не был подписан Глушковым из-за очевидной политической ошибочности и неэкономичности. Все же авторов технических параграфов этого проекта пионер кибернетики консультировал, а это значит, что с большой осторожностью можно некоторые взгляды Глушкова на вычислительную технику того времени реконструировать через именно технические параграфы этого проекта. В частности если сравнить их с тезисами именно в его "Основах безбумажной информатики", которые он создавал за несколько лет перед смертью.',-1),i=(0,l._)("p",null,"Отдельной архитектуры хранения данных проект ОГАС 1980 года не приводит, речь идет преимущественно о линиях связи. Именно они настолько отставали от замысла Глушкова, что ведущую роль в инфраструктурной работе по ОГАС должно было играть министерство связи СССР. Там, где связь позволяла, средства хранения данных строились на ленточных накопителях как основных и жестких дисках как дополнительных (полуоперативных) накопителях данных. Емкость и надежность этих носителей на конец 1970-х годов обуславливала распространение иерархических баз данных, передовые системы управления которыми примерно тогда приобретали полноценную транзакционность. Чтобы представить возможный демократизм иерархической модели данных (как перспективу тех средств), надо вспомнить, что своеобразными современными наследниками иерархических СУБД ОКА(СССР) и РОДАН(ПНР) являются форматы хранения данных XML и JSON а также файловая система. Это крайне плохая техническая основа обобществления данных, потому что сейчас она в крупных организациях не употребляется как главная, а преимущественно и как дополнительная тоже. К тому надо добавить, что Глушков рассматривал ОГАС как средство преодоления общественной иерархии и товарно-денежных отношений в обществе. Получается, что иерархические СУБД подобные СУБД ОКА, на которых Глушков собирался строить архитектуру хранения данных отрицаются сейчас сразу с двух сторон. Во-первых, как технически устаревшие и непригодные для большого обобществления, во-вторых, иерархическая БД с независимыми ветвями и секторами ответственности плохо популяризируется и поддерживает своим иерархическим построением разделение труда именно там, где Глушков считал общественную иерархию исчерпанной. Есть и другие факторы: процесс познания иерархических структур данных и количество работы по программированию. Начнем с того, что иерархические структуры (например, файловая система) крайне плохо типизируются. Типизация здесь является внешним дополнением, как XSD к XML, в то время как реляционная модель данных состоит исключительно или преимущественно из типизированных данных. Иерархические структуры данных складываются эмпирическим образом, то есть знание о порядке данных формируется, когда они уже расположены. Таким образом формирование (получение формы) данных обуславливает также содержание труда по программированию применения соответствующих данных. Такое программирование строится на адресном принципе (выделить ветку и значение) и требует дополнительной типизации в противовес тому, что реляционные структуры не требуют указания сложных ветвистых координат и сразу имеют нужную типизацию. Относительно иерархических структур сущность реляционных структур данных заключается в противоположном. Они составляются теоретическим образом, то есть после того, как автор БД понял сущность и изменяемость того что она выражает.",-1),u=(0,l._)("p",null,'В "Основах безбумажной информатики", которые распространялись в один год со стандартом SQL-82 в Соединенных Штатах Америки, Глушков затрагивает реляционную модель данных только как математическую концепцию и приводит математические формулы по преобразованию иерархических структур данных в реляционные. Очевидно также, что эффективные технические реализации реляционной модели данных пригодные для ОГАС Глушков на время своей смерти не знал. Советские файловые СУБД СИОД и ДИСОД все еще оставались не очень эффективными в ресурсно-математическом, а также в частности в общественном смысле, то есть недемократическими (их было трудно усваивать). В США, где Стовнбейкер в 1987 году создал основу для СУБД Постгресс ситуация не была отличной. Лишь через 10 лет Постгресс научили хранить данные на всех распространенных системах письменности и, в том числе, называть внутренние объекты БД на всех распространенных языках. Транзакционная архитектура СУБД Постгресс, которая недавно получила механизм репликации на несколько узлов гораздо более пригодна для реализации хранения данных в распределенных вычислительных центрах о которых писал Глушков. Не только в политике, но и в технике автор "Основ безбумажной информатики" опередил свое физическое время на несколько десятилетий.',-1),h=(0,l._)("h2",{id:"список-использованных-источников",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#список-использованных-источников","aria-hidden":"true"},"#"),(0,l.Uk)(" Список использованных источников")],-1),d=(0,l._)("ol",null,[(0,l._)("li",null,[(0,l._)("p",null,"Глушков В.М. Основы безбумажной информатики Изд-е 2-е, исправленное - М.: Наука, Гл.ред физ.-мат. лит., 1987. - 552 с.")]),(0,l._)("li",null,[(0,l._)("p",null,"Иванов В.К., Наумов А.Н., Вендров А.М. Программное обеспечение банков данных (прагматический подход) Международный научно-практический журнал Программные продукты и системы № 3 1988 г. ISSN 0236-235X См. также http://swsys.ru/index.php?page=article&id=1472")])],-1),s={},p=(0,e(3744).Z)(s,[["render",function(D,B){const e=(0,l.up)("ExternalLinkIcon");return(0,l.wg)(),(0,l.iD)("div",null,[a,(0,l._)("p",null,[(0,l.Uk)("Микола Загорський (Mikołaj Zagorski). Перевод с украинского. "),(0,l._)("a",r,[(0,l.Uk)("Двуязычная версия"),(0,l.Wm)(e)]),(0,l.Uk)(".")]),t,n,i,u,h,d])}]])}}]);